rules.to:
(
  $defaultVolumes := [
    {
      "host": msg.host_id,
      "name": msg.instanceShort & "-data"
    }
  ];
  $formVolumes := $type(msg.volume_name) = "array" ? $append([], $filter($map(msg.volume_name, function($name) {
    {
      "host": msg.host_id,
      "name": $name
    }
  }), function($volume) { $volume.name })) : (msg.volume_name ? [
    {
      "host": msg.host_id,
      "name": msg.volume_name
    }
  ] : []);
  $volumes := $count($formVolumes) > 0 ? $formVolumes : $defaultVolumes;
  $count($volumes) = 1 ? $volumes[0] : $volumes
)

(
  $defaultMounts := [
    {
      "source": "/app/data",
      "volume": {
        "name": msg.instanceShort & "-data"
      },
      "read_only": false
    }
  ];
  $formMounts := $type(msg.volume_source) = "array" ? $append([], $filter($map(msg.volume_source, function($source, $i) {
    {
      "source": $source,
      "volume": {
        "name": msg.volume_name[$i]
      },
      "read_only": false
    }
  }), function($mount) { $mount.source and $mount.volume.name })) : (msg.volume_source and msg.volume_name ? [
    {
      "source": msg.volume_source,
      "volume": {
        "name": msg.volume_name
      },
      "read_only": false
    }
  ] : []);
  $env := $type(msg.var_env_key) = "array" ? $append([], $filter($map(msg.var_env_key, function($key, $i) {
    {
      "var_name": $key,
      "value": msg.var_env_value[$i]
    }
  }), function($item) { $item.var_name })) : (msg.var_env_key ? [
    {
      "var_name": msg.var_env_key,
      "value": msg.var_env_value
    }
  ] : []);
  $baseLabels := [
    {
      "key": "traefik.enable",
      "value": "true"
    },
    {
      "key": "traefik.http.routers." & msg.instanceShort & ".rule",
      "value": "Host(`" & msg.instance & "`)"
    },
    {
      "key": "traefik.http.routers." & msg.instanceShort & ".entrypoints",
      "value": "http"
    },
    {
      "key": "traefik.http.services." & msg.instanceShort & ".loadbalancer.server.port",
      "value": "3000"
    },
    {
      "key": "traefik.http.middlewares.force-https-header.headers.customrequestheaders.X-Forwarded-Proto",
      "value": "https"
    },
    {
      "key": "traefik.http.middlewares." & msg.instanceShort & ".ipallowlist.sourcerange",
      "value": "173.245.48.0/20, 103.21.244.0/22, 103.22.200.0/22, 103.31.4.0/22, 141.101.64.0/18, 108.162.192.0/18, 190.93.240.0/20, 188.114.96.0/20, 197.234.240.0/22, 198.41.128.0/17, 162.158.0.0/15, 104.16.0.0/13, 104.24.0.0/14, 172.64.0.0/13, 131.0.72.0/22, 2400:cb00::/32, 2606:4700::/32, 2803:f800::/32, 2405:b500::/32, 2405:8100::/32, 2a06:98c0::/29, 2c0f:f248::/32"
    },
    {
      "key": "traefik.http.routers." & msg.instanceShort & ".middlewares",
      "value": "force-https-header," & msg.instanceShort
    }
  ];
  $extraLabels := $type(msg.label_key) = "array" ? $append([], $filter($map(msg.label_key, function($key, $i) {
    {
      "key": $key,
      "value": msg.label_value[$i]
    }
  }), function($label) { $label.key })) : (msg.label_key ? [
    {
      "key": msg.label_key,
      "value": msg.label_value
    }
  ] : []);
  [
    {
      "id": msg.container.id,
      "host": msg.host_id,
      "network_settings": [
        {
          "network": {
            "host": msg.host_id,
            "name": msg.network
          }
        }
      ],
      "mounts": $count($formMounts) > 0 ? $formMounts : $defaultMounts,
      "env": $env,
      "labels": $append($baseLabels, $extraLabels)
    }
  ]
)
